sql:
SELECT assessment_id
FROM assessment_tags
WHERE tag = 'cognitive function';

SELECT COUNT(*)
FROM assessment_tags
WHERE tag = 'nutrition';

external_knowledge:
- "flourishing topics" refers to topics with high average scores and a large number of questions;
- "average score" is the mean score achieved by users across all assessments for a given topic;
- "number of questions" refers to the total count of questions associated with each topic.
